import React, { useState, useEffect } from 'react';
import {
  Card,
  CardContent,
  Typography,
  Button,
  Grid,
  IconButton,
  Divider,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import RemoveIcon from '@mui/icons-material/Remove';

export default function POS({ outletId }) {
  const [products, setProducts] = useState([]);
  const [cart, setCart] = useState([]);

  // ডামি ডেটা ফেচিং (ব্যাকএন্ড থেকে outlet_products টেবিলে জয়েন করে আসবে)
  useEffect(() => {
    // API Call: GET /api/outlets/${outletId}/products
    const fetchOutletProducts = async () => {
      setProducts([
        {
          outlet_products_id: 1,
          name: 'Latte',
          price: 250,
          stock_quantity: 15,
        },
        {
          outlet_products_id: 2,
          name: 'Espresso',
          price: 180,
          stock_quantity: 5,
        },
        {
          outlet_products_id: 3,
          name: 'Cheesecake',
          price: 300,
          stock_quantity: 2,
        }, // Low stock scenario
      ]);
    };
    fetchOutletProducts();
  }, [outletId]);

  const addToCart = (product) => {
    const existingItem = cart.find(
      (item) => item.outlet_products_id === product.outlet_products_id
    );
    const currentQty = existingItem ? existingItem.qty : 0;

    // Prevent Negative Stock on Frontend
    if (currentQty + 1 > product.stock_quantity) {
      alert(`Cannot add more! Only ${product.stock_quantity} in stock.`);
      return;
    }

    if (existingItem) {
      setCart(
        cart.map((item) =>
          item.outlet_products_id === product.outlet_products_id
            ? { ...item, qty: item.qty + 1 }
            : item
        )
      );
    } else {
      setCart([...cart, { ...product, qty: 1 }]);
    }
  };

  const removeFromCart = (id) => {
    const existingItem = cart.find((item) => item.outlet_products_id === id);
    if (existingItem.qty === 1) {
      setCart(cart.filter((item) => item.outlet_products_id !== id));
    } else {
      setCart(
        cart.map((item) =>
          item.outlet_products_id === id ? { ...item, qty: item.qty - 1 } : item
        )
      );
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price * item.qty, 0);

  const handleCheckout = () => {
    const payload = {
      outlet_id: outletId,
      user_id: 1, // Logged in user ID (cashier)
      items: cart.map((item) => ({
        outlet_products_id: item.outlet_products_id,
        qty: item.qty,
        unit_price: item.price,
      })),
    };
    console.log(
      'API Call: POST /api/sales - Checkout Transaction Wrap',
      payload
    );
    alert(`Sale Completed! Receipt No generated.`);
    setCart([]); // Reset cart after successful sale
  };

  return (
    <Grid container spacing={4}>
      {/* প্রোডাক্ট গ্রিড */}
      <Grid item xs={12} md={8}>
        <Typography variant="h5" className="font-bold mb-4">
          Menu Items
        </Typography>
        <Grid container spacing={3}>
          {products.map((product) => (
            <Grid item xs={12} sm={6} md={4} key={product.outlet_products_id}>
              <Card className="hover:shadow-lg transition-shadow duration-200">
                <CardContent className="flex flex-col items-center p-6">
                  <Typography
                    variant="h6"
                    className="font-semibold text-center"
                  >
                    {product.name}
                  </Typography>
                  <Typography color="textSecondary">
                    ৳{product.price}
                  </Typography>
                  <Typography
                    variant="body2"
                    className={`mt-1 mb-3 ${product.stock_quantity < 5 ? 'text-red-500 font-bold' : 'text-gray-500'}`}
                  >
                    Stock: {product.stock_quantity}
                  </Typography>
                  <Button
                    variant="outlined"
                    fullWidth
                    disabled={product.stock_quantity === 0}
                    onClick={() => addToCart(product)}
                  >
                    Add to Cart
                  </Button>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Grid>

      {/* কার্ট এবং চেকআউট */}
      <Grid item xs={12} md={4}>
        <Card className="sticky top-4 shadow-md bg-white">
          <CardContent className="flex flex-col h-[80vh]">
            <Typography variant="h5" className="font-bold mb-4">
              Current Sale
            </Typography>
            <Divider className="mb-4" />

            <div className="flex-grow overflow-y-auto">
              {cart.length === 0 ? (
                <Typography color="textSecondary" className="text-center mt-10">
                  Cart is empty
                </Typography>
              ) : (
                cart.map((item) => (
                  <div
                    key={item.outlet_products_id}
                    className="flex justify-between items-center mb-4"
                  >
                    <div className="flex-1">
                      <Typography variant="subtitle1" className="font-semibold">
                        {item.name}
                      </Typography>
                      <Typography variant="body2" color="textSecondary">
                        ৳{item.price} x {item.qty}
                      </Typography>
                    </div>
                    <div className="flex items-center bg-gray-100 rounded">
                      <IconButton
                        size="small"
                        onClick={() => removeFromCart(item.outlet_products_id)}
                      >
                        <RemoveIcon fontSize="small" />
                      </IconButton>
                      <Typography className="px-2 font-bold">
                        {item.qty}
                      </Typography>
                      <IconButton size="small" onClick={() => addToCart(item)}>
                        <AddIcon fontSize="small" />
                      </IconButton>
                    </div>
                  </div>
                ))
              )}
            </div>

            <Divider className="my-4" />
            <div className="flex justify-between items-center mb-6">
              <Typography variant="h6" className="font-bold">
                Total:
              </Typography>
              <Typography variant="h5" className="font-bold text-green-600">
                ৳{cartTotal}
              </Typography>
            </div>

            <Button
              variant="contained"
              color="success"
              size="large"
              fullWidth
              disabled={cart.length === 0}
              onClick={handleCheckout}
              className="py-3 text-lg font-bold"
            >
              Checkout & Pay
            </Button>
          </CardContent>
        </Card>
      </Grid>
    </Grid>
  );
}
